    private void btnCerrarSesionActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnCerrarSesionActionPerformed
        coordinadorVistas.rolLogueado = "";
        coordinadorVistas.mostrarInicioSesion(this);
    }//GEN-LAST:event_btnCerrarSesionActionPerformed

    private void btnSeleccionarOpcionResidenteActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSeleccionarOpcionResidenteActionPerformed

        if (cmbxGestionResidentes.getSelectedItem() == null) {
            javax.swing.JOptionPane.showMessageDialog(this,
                    "Selecciona una opción de gestión de residentes.",
                    "Opción requerida",
                    javax.swing.JOptionPane.WARNING_MESSAGE);
            return;
        }

        String opcion = cmbxGestionResidentes.getSelectedItem().toString();

        if (opcion.equalsIgnoreCase("Selecciona una opción")
                || opcion.equalsIgnoreCase("Seleccionar")
                || opcion.contains("Selecciona")) {

            javax.swing.JOptionPane.showMessageDialog(this,
                    "Selecciona una opción de gestión de residentes.",
                    "Opción requerida",
                    javax.swing.JOptionPane.WARNING_MESSAGE);
            return;
        }

        switch (opcion) {
            case "Registrar residente":
                coordinadorVistas.mostrarCrearResidente(this);
                break;

            case "Modificar residente":
                coordinadorVistas.mostrarModificarResidente(this);
                break;

            case "Consultar residente":
                coordinadorVistas.mostrarConsultarResidente(this);
                break;

            default:
                javax.swing.JOptionPane.showMessageDialog(this,
                        "La opción seleccionada no está disponible para el rol Trabajador.",
                        "Acceso no permitido",
                        javax.swing.JOptionPane.WARNING_MESSAGE);
                break;
        }


    }//GEN-LAST:event_btnSeleccionarOpcionResidenteActionPerformed

